solution_code:
#include <string.h>
#include <stdio.h>

int build_error_msg(char *buf, size_t sz) {
    int code = 404;
    char *path = "/proc/42/status";
    int pid = 42;
    return snprintf(buf, sz, "[ERR-%d] Not found: %s (pid=%d)", code, path, pid);
}

int build_small_error(char *buf, size_t sz) {
    int pid = 42;
    return snprintf(buf, sz, "pid=%d cmd=%s", pid, "very_long_name_here");
}

int main(void) {
    {
        char buf[128];
        build_error_msg(buf, sizeof(buf));
        printf("%s\n", buf);
    }
    {
        char buf[128];
        int ret = build_error_msg(buf, sizeof(buf));
        printf("%d\n", (int)(ret));
    }
    {
        char buf[20];
        int ret = build_small_error(buf, sizeof(buf));
        printf("%d\n", (ret >= (int)sizeof(buf)) ? 1 : 0);
    }
    {
        char buf[20];
        build_small_error(buf, sizeof(buf));
        printf("%d\n", (int)(strlen(buf)));
    }
    return 0;
}

